(window["webpackJsonp"]=window["webpackJsonp"]||[]).push([["sintesis"],{"15a3":function(a,i,e){"use strict";e.r(i);var s=function(){var a=this,i=a._self._c;return i("div",{staticClass:"curso-main-container pb-3"},[i("BannerInterno",{attrs:{icono:"fas fa-sitemap",titulo:"Síntesis"}}),i("div",{staticClass:"container tarjeta tarjeta--blanca p-4 p-md-5"},[i("p",{staticClass:"mb-3"},[a._v("El componente formativo Planeación organizacional y gestión de procesos participativos aborda los fundamentos conceptuales, metodológicos y técnicos necesarios para reconocer, analizar y estructurar modelos organizacionales en contextos rurales y comunitarios. Su propósito es fortalecer las capacidades de los aprendices para comprender el funcionamiento de las organizaciones, identificar las características del entorno y formular estrategias que contribuyan al desarrollo organizacional y territorial. En este componente se estudian conceptos relacionados con el desarrollo rural, la organización comunitaria, la asociatividad y el marco normativo que orienta los procesos de extensión agropecuaria y fortalecimiento organizacional. Asimismo, se analizan herramientas de diagnóstico participativo que permiten identificar actores, caracterizar el entorno, reconocer necesidades y analizar problemáticas mediante metodologías participativas que favorecen la construcción colectiva de información y la toma de decisiones.")]),i("p",{staticClass:"mb-3"},[a._v("De igual manera, el componente aborda los diferentes modelos organizacionales, sus características y formas de aplicación en organizaciones rurales y comunitarias. Se estudian criterios técnicos, herramientas e indicadores que facilitan el análisis organizacional, así como elementos relacionados con el trabajo en equipo, la definición de roles y responsabilidades, el liderazgo, la comunicación y las estrategias de participación colaborativa orientadas al fortalecimiento de los procesos organizativos. Finalmente, se desarrollan contenidos asociados a la planeación estratégica y la formulación de planes de acción, incluyendo la definición de objetivos, metas, estrategias, actividades e indicadores de seguimiento. Asimismo, se promueve la utilización de técnicas e instrumentos de planeación participativa que permitan articular las necesidades del territorio con los procesos organizacionales, fortaleciendo la capacidad de gestión, la participación comunitaria y la sostenibilidad de las iniciativas rurales y comunitarias.")]),i("div",{staticClass:"row justify-content-center"},[a._m(0),i("div",{staticClass:"col-auto"},[i("a",{staticClass:"anexo mb-5",attrs:{href:a.obtenerLink("/downloads/Sintesis.pdf"),target:"_blank"}},[a._m(1),a._m(2)])])])])],1)},n=[function(){var a=this,i=a._self._c;return i("div",{staticClass:"col-12 mb-5 bgs p-4 brad"},[i("figure",[i("img",{attrs:{src:e("cc8e"),alt:"Lorem ipsum dolor sit amet, consectetur adipiscing elit. Mauris eu tincidunt erat. Fusce cursus mauris in nulla egestas vulputate. Phasellus viverra accumsan libero, sed luctus diam maximus euismod. Mauris sem risus, tincidunt vel libero in, lobortis commodo ante. Sed pulvinar luctus orci in rhoncus. Nulla ut dapibus risus, ac tempor est. Donec nulla augue, vehicula quis malesuada vitae, fermentum non nisi. Donec tincidunt nibh a magna bibendum rutrum. "}})])])},function(){var a=this,i=a._self._c;return i("div",{staticClass:"anexo__icono"},[i("img",{attrs:{src:e("abd8")}})])},function(){var a=this,i=a._self._c;return i("div",{staticClass:"anexo__texto"},[i("p",[a._v("Anexo. Síntesis")])])}],o={name:"Sintesis",data:()=>({}),mounted(){this.$nextTick(()=>{this.$aosRefresh()})},updated(){this.$aosRefresh()}},t=o,r=e("2877"),c=Object(r["a"])(t,s,n,!1,null,null,null);i["default"]=c.exports},abd8:function(a,i,e){a.exports=e.p+"img/icono-pdf.82f139cb.svg"},cc8e:function(a,i,e){a.exports=e.p+"img/sintesis.564dd37a.svg"}}]);
